// ─── Archetype collection ─────────────────────────────────────────────────────
function xorBin(a, b) {
let r = “”;
for (let i = 0; i < BIN_LEN; i++) r += (a[i] === b[i]) ? “0” : “1”;
return r;
}
function transmute(a, b, c) { return xorBin(xorBin(a, b), c); }

const _acCache = new Map();
function ac(who, where, when) {
const k = who + where + when;
if (_acCache.has(k)) return _acCache.get(k);
const v = `hsl(${WHO_HUE[who]},${WHERE_SAT[where]}%,${WHEN_LIT[when]}%)`;
_acCache.set(k, v);
return v;
}

const ALL = [];
for (const [wb, wn] of Object.entries(WHO_MAP))
for (const [rb, rn] of Object.entries(WHERE_MAP))
for (const [eb, en] of Object.entries(WHEN_MAP)) {
const b = wb + rb + eb;
ALL.push({ bin: b, who: wn, where: rn, when: en, name: NAMES[b], key: KEYS[b] });
}

const ARCH_MAP = new Map(ALL.map(a => [a.bin, a]));
const ga = bin => ARCH_MAP.get(bin) || ALL[0];

function getInspiration(ing1, ing2, targetBin) {
const needBin = transmute(ing1.bin, ing2.bin, targetBin);
const need = ga(needBin);
if (!need) return null;
const sameWho = need.who === ing1.who && need.who === ing2.who;
return {
bin: needBin, name: need.name, key: need.key,
who: need.who, where: need.where, when: need.when,
line1: sameWho
? `Залишається з роду «${WHO_POETIC[need.who]}»`
: `Шукай у роді «${WHO_POETIC[need.who]}»`,
line2: `${WHERE_POETIC[need.where]}, ${WHEN_POETIC[need.when]}`,
line3: `Ключ: «${need.key}»`,
};
}

