// ═══════════════════════════════════════════════════════════════════════════════
// SECTION 3 — AUDIO ENGINE
// ═══════════════════════════════════════════════════════════════════════════════

// ═══ AUDIO ENGINE v5 ═══
let _AC = null;
let _MG = null;
let _RV = null;
let _vol = 0.75;

function _ctx() {
if (!_AC) {
try { _AC = new (window.AudioContext||window.webkitAudioContext)(); }
catch(e) { return null; }
}
if (_AC.state === ‘closed’) {
_AC = null; _MG = null; _RV = null;
try { _AC = new (window.AudioContext||window.webkitAudioContext)(); }
catch(e) { return null; }
}
return _AC;
}

function _mg() {
const c = _ctx(); if (!c) return null;
if (!_MG || _MG.context !== c) {
try { _MG = c.createGain(); _MG.gain.value = _vol; _MG.connect(c.destination); }
catch(e) { _MG = null; }
}
return _MG;
}

function _rv() {
const c = _ctx(); if (!c) return null;
if (_RV && _RV.context === c) return _RV;
try {
const sr = c.sampleRate, len = Math.floor(sr * 1.4);
const buf = c.createBuffer(2, len, sr);
for (let ch = 0; ch < 2; ch++) {
const d = buf.getChannelData(ch);
for (let i = 0; i < len; i++) d[i] = (Math.random()*2-1) * Math.pow(1-i/len, 1.8);
}
_RV = c.createConvolver(); _RV.buffer = buf;
const g = c.createGain(); g.gain.value = 0.45;
_RV.connect(g); g.connect(_mg());
} catch(e) { _RV = null; }
return _RV;
}

const setMasterVol = (v) => {
_vol = Math.max(0, Math.min(1, v));
const mg = _mg(); if (!mg) return;
const c = _ctx(); if (!c) return;
try { mg.gain.setTargetAtTime(_vol, c.currentTime, 0.1); } catch(e) { mg.gain.value = _vol; }
};

// Play tone — resumes ctx first if needed, THEN schedules
function _tone(freq, type, dur, vol, delay=0, wet=0) {
const c = _ctx(); if (!c) return;
const play = () => {
const mg = _mg(); if (!mg) return;
try {
const o = c.createOscillator(), g = c.createGain();
o.type = type; o.frequency.value = Math.max(20, freq);
const t = c.currentTime + Math.max(0, delay);
g.gain.setValueAtTime(0, t);
g.gain.linearRampToValueAtTime(vol, t + 0.012);
g.gain.setValueAtTime(vol, t + dur * 0.65);
g.gain.exponentialRampToValueAtTime(0.0001, t + dur);
o.connect(g); g.connect(mg);
if (wet > 0) { const rv = _rv(); if (rv) { const rg = c.createGain(); rg.gain.value = wet; g.connect(rg); rg.connect(rv); } }
o.onended = () => { try { g.disconnect(); o.disconnect(); } catch(e) {} };
o.start(t); o.stop(t + dur + 0.15);
} catch(e) {}
};
if (c.state === ‘running’) { play(); }
else { c.resume().then(play).catch(()=>{}); }
}

// Noise burst
function _burst(dur, vol, delay=0, freq=500, q=1, wet=0) {
const c = _ctx(); if (!c) return;
const play = () => {
const mg = _mg(); if (!mg) return;
try {
const buf = c.createBuffer(1, Math.ceil(c.sampleRate*(dur+0.1)), c.sampleRate);
const ch = buf.getChannelData(0);
for (let i = 0; i < ch.length; i++) ch[i] = Math.random()*2-1;
const src = c.createBufferSource(); src.buffer = buf;
const flt = c.createBiquadFilter(); flt.type = ‘bandpass’; flt.frequency.value = freq; flt.Q.value = q;
const g = c.createGain(); src.connect(flt); flt.connect(g); g.connect(mg);
const t = c.currentTime + Math.max(0, delay);
g.gain.setValueAtTime(0, t); g.gain.linearRampToValueAtTime(vol, t+0.015);
g.gain.exponentialRampToValueAtTime(0.0001, t+dur);
if (wet > 0) { const rv = _rv(); if (rv) { const rg = c.createGain(); rg.gain.value = wet; g.connect(rg); rg.connect(rv); } }
src.start(t); src.stop(t+dur+0.15);
src.onended = () => { try { g.disconnect(); flt.disconnect(); src.disconnect(); } catch(e) {} };
} catch(e) {}
};
if (c.state === ‘running’) { play(); }
else { c.resume().then(play).catch(()=>{}); }
}

const haptic = (p) => { try { if (navigator.vibrate) navigator.vibrate(p); } catch(e) {} };

function _unlock() {
const c = _ctx(); if (!c) return;
if (c.state === ‘suspended’) c.resume().then(()=>{ _mg(); _rv(); }).catch(()=>{});
else { _mg(); }
}
[‘click’,‘touchend’,‘keydown’,‘pointerdown’].forEach(ev =>
document.addEventListener(ev, _unlock, { capture:true, passive:true })
);

