const Music = {
_loop:null, _season:null, _heat:60, _on:true,
setVolume(v) { setMasterVol(v); },
setHeat(h)   { this._heat = h; },
setEnabled(v){ this._on = v; if (!v) this.stopAll(); else { _unlock(); setMasterVol(_vol); } },

_note(freq, t, dur, type, vol, ps=1) {
const c = _ctx(); const mg = _mg(); if (!c||!mg||c.state!==‘running’) return;
try {
const o = c.createOscillator(), g = c.createGain();
const lfo = c.createOscillator(), lg = c.createGain();
lfo.frequency.value = 4.5; lg.gain.value = freq * 0.004;
lfo.connect(lg); lg.connect(o.frequency); lfo.start(t); lfo.stop(t+dur+0.1);
lfo.onended = () => { try{lg.disconnect();lfo.disconnect();}catch(e){} };
o.type = type; o.frequency.value = Math.max(20, freq*ps);
g.gain.setValueAtTime(0,t); g.gain.linearRampToValueAtTime(vol,t+0.025);
g.gain.setValueAtTime(vol,t+dur*0.72); g.gain.exponentialRampToValueAtTime(0.0001,t+dur);
o.connect(g); g.connect(mg);
if (_RV) { const rg=c.createGain(); rg.gain.value=0.12; g.connect(rg); rg.connect(_RV); }
o.start(t); o.stop(t+dur+0.1);
o.onended = ()=>{ try{g.disconnect();o.disconnect();}catch(e){} };
} catch(e) {}
},

_motif(season, c) {
const p = SEASON_PATTERNS[season]; if (!p) return;
const now = c.currentTime;
const tempo = 0.7 + (this._heat/MAX_HEAT)*0.7;
const ps    = 1   + (this._heat/MAX_HEAT)*0.14;
const nl = 4.0 / p.mel.length;
p.mel.slice(0,4).forEach((f,i) => this._note(f, now+i*nl/tempo, nl*0.88/tempo, p.t,  p.v,  ps));
p.bas.slice(0,4).forEach((f,i) => this._note(f, now+i*nl/tempo, nl*0.92/tempo, p.bt, p.bv, ps*0.5));
},

startBackground(season) {
this.stopBackground();
if (!season || !this._on) return;
this._season = season;
const self = this;
const doPlay = () => {
if (self._season !== season) return;
const c = _ctx(); const mg = _mg();
if (!c || !mg) { self._loop = setTimeout(doPlay, 2000); return; }
if (c.state !== ‘running’) {
c.resume().then(doPlay).catch(()=>{ self._loop = setTimeout(doPlay, 2000); });
return;
}
// drone
try {
const p = SEASON_PATTERNS[season];
const o = c.createOscillator(), g = c.createGain();
o.type = ‘sine’; o.frequency.value = p.bas[0] * (1+(self._heat/MAX_HEAT)*0.08);
const now = c.currentTime;
g.gain.setValueAtTime(0,now); g.gain.linearRampToValueAtTime(0.048,now+2.5);
g.gain.setValueAtTime(0.048,now+5); g.gain.linearRampToValueAtTime(0,now+7.5);
o.connect(g); g.connect(mg); o.start(now); o.stop(now+7.6);
o.onended = ()=>{ try{g.disconnect();o.disconnect();}catch(e){}};
} catch(e) {}
self._motif(season, c);
self._loop = setTimeout(doPlay, 8500);
};
this._loop = setTimeout(doPlay, 300);
},

stopBackground(){ if(this._loop){clearTimeout(this._loop);this._loop=null;} this._season=null; },

_droneO:null, _droneG:null,
startHeatDrone() {
if (!this._on) return;
const c = _ctx(); const mg = _mg();
if (!c || !mg || c.state !== ‘running’) return;
this.stopHeatDrone();
try {
const o = c.createOscillator(), g = c.createGain();
o.type = ‘sine’; o.frequency.value = 42+(this._heat/MAX_HEAT)*75;
g.gain.setValueAtTime(0,c.currentTime); g.gain.linearRampToValueAtTime(0.028,c.currentTime+1.5);
o.connect(g); g.connect(mg); o.start(c.currentTime);
this._droneO=o; this._droneG=g;
} catch(e) {}
},
updateHeatDrone(heat) {
this._heat = heat;
if (!this._droneO) return;
const c = _ctx(); if (!c) return;
try {
this._droneO.frequency.setTargetAtTime(42+(heat/MAX_HEAT)*75, c.currentTime, 0.3);
this._droneG.gain.setTargetAtTime(0.020+(heat>300?0.014:0), c.currentTime, 0.4);
} catch(e) {}
},
stopHeatDrone() {
if (!this._droneO) return;
const c = _ctx();
try {
if (c) this._droneG.gain.setTargetAtTime(0, c.currentTime, 0.3);
setTimeout(()=>{ try{this._droneO.stop();}catch(e){} this._droneO=null; this._droneG=null; }, 500);
} catch(e) { this._droneO=null; this._droneG=null; }
},
stopAll() { this.stopBackground(); this.stopHeatDrone(); },
playTheme(when, dur) { /* stub — resonance handled by SFX.resonance */ },
playTransition(from, to) {
if (!this._on) return;
const pF=SEASON_PATTERNS[from], pT=SEASON_PATTERNS[to]; if(!pF||!pT) return;
const c=_ctx(); if(!c||c.state!==‘running’) return;
const now = c.currentTime;
[pF.bas[0],pF.mel[0],pF.mel[2]].forEach((f,i)=>this._note(f,now+i*0.10,1.5,pF.t,0.09*(1-i*0.2)));
[pT.bas[0],pT.mel[0],pT.mel[2]].forEach((f,i)=>this._note(f,now+1.3+i*0.12,1.8,pT.t,0.10*(1-i*0.15)));
},
};

