function gsReducer(state,action){
switch(action.type){
case “UPDATE”: return action.fn(state);
case “RESET”:  return action.payload;
default: return state;
}
}

let _activeSounds = 0;
const _guardedNode = (f, t, d, v, dl=0, wet=0) => {
if (_activeSounds >= 8) return;
_activeSounds++;
_tone(f, t, d, v, dl, wet);
setTimeout(() => { _activeSounds = Math.max(0, _activeSounds - 1); }, (dl + d) * 1000 + 100);
};

function playArchSound(arch) {
const p = getArchSoundParams(arch);
_guardedNode(p.freq, p.type, p.dur, p.vol);
}

